mapper.insert:
INSERT INTO enrollments (
        user_id
      , course_id
      , status
) VALUES (
        #{userId}
      , #{courseId}
      , #{status}
)

mapper.update:
UPDATE enrollments
   SET status = #{status}
     , confirmed_at = #{confirmedAt}
     , cancelled_at = #{cancelledAt}
 WHERE id = #{id}

UPDATE enrollments
   SET status = #{status}
     , confirmed_at = #{confirmedAt}
     , cancelled_at = #{cancelledAt}
 WHERE id = #{id}
   AND status = 'CANCELLED'

mapper.select:
SELECT COUNT(*)
  FROM enrollments
 WHERE course_id = #{courseId}

SELECT COUNT(*)
  FROM enrollments
 WHERE user_id = #{userId}
